/// <reference path="../typings/index.d.ts" />
import {BeSkill, Options} from '@be/be-framework';
import jibo = require('jibo');
import ServerController from './ServerController';
import Analytics from './analytics/Analytics';

let mainFlow:any = require('./flows/main');

class IFTTT extends BeSkill {

    public flow:jibo.flow.FlowExecutor = null;
    public server:ServerController;
    private analytics:Analytics;

    get allowedInterrupts():string[] {
        return ['@be/idle'];
    }

    /**
     * Template skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?:Options) {
        super(assetPack);

        this.analytics = new Analytics(this);
    }

    preload(done:(err?:any)=>void):void {
        done();
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?:any):void {
        this.server = new ServerController(Date.now(), this.log);
        let trigger:string;
        if (result && result.nlu) {
            trigger = result.nlu.entities.slotAction;
        } else {
            this.exit();
            return;
        }

        //track which command was used - using nlu is safe at this point
        this.analytics.recipeTriggered(result.nlu.entities.command);

        const options = {
            assetPack: this.assetPack,
            enableLogging: false,
            blackboard: {
                server: this.server,
                trigger
            }
        };
        this.flow = jibo.flow.run(mainFlow, options, () => {
        this.exit();
        });
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done:() => void):void {
        if (this.flow) {
            const flow = this.flow;
            this.flow = null;
            flow.stop().then(() => {
                flow.destroy();
                done();
            }, () => {
                done();
            });
        }
        this.server = null;
    }
}

module.exports = IFTTT;
